B.MA=new A.z(1,0.050980392156862744,0.5803921568627451,0.5333333333333333,B.i)
B.Ru=new A.Z("A comprehensive product traceability platform for manufacturing operations. The system generates unique 2D barcodes for each product unit based on product type and attributes, sends them to industrial Jet Printers for on-product labeling, and uses camera scanning on the production line. When the configured number of units per carton is reached, it automatically generates a unique master carton barcode and sends it to a label printer. Warehouse, distribution, and returns departments update product status by scanning these barcodes, with full reporting and analytics built in.","\u067e\u0644\u062a\u0641\u0631\u0645 \u062c\u0627\u0645\u0639 \u0631\u062f\u06cc\u0627\u0628\u06cc \u0645\u062d\u0635\u0648\u0644 \u0628\u0631\u0627\u06cc \u0639\u0645\u0644\u06cc\u0627\u062a \u062a\u0648\u0644\u06cc\u062f. \u0628\u0631\u0627\u06cc \u0647\u0631 \u0648\u0627\u062d\u062f \u0645\u062d\u0635\u0648\u0644 \u0628\u0631 \u0627\u0633\u0627\u0633 \u0646\u0648\u0639 \u0648 \u0645\u0634\u062e\u0635\u0627\u062a\u060c \u0628\u0627\u0631\u06a9\u062f \u062f\u0648\u0628\u0639\u062f\u06cc \u06cc\u0648\u0646\u06cc\u06a9 \u062a\u0648\u0644\u06cc\u062f \u0645\u06cc\u200c\u06a9\u0646\u062f \u0648 \u0628\u0647 Jet Printer \u0635\u0646\u0639\u062a\u06cc \u0628\u0631\u0627\u06cc \u0686\u0627\u067e \u0631\u0648\u06cc \u0645\u062d\u0635\u0648\u0644 \u0627\u0631\u0633\u0627\u0644 \u0645\u06cc\u200c\u06a9\u0646\u062f. \u0628\u0627 \u0627\u0633\u06a9\u0646 \u062f\u0648\u0631\u0628\u06cc\u0646 \u062f\u0631 \u062e\u0637 \u062a\u0648\u0644\u06cc\u062f\u060c \u0648\u0642\u062a\u06cc \u0628\u0647 \u062a\u0639\u062f\u0627\u062f \u062a\u0639\u0631\u06cc\u0641\u200c\u0634\u062f\u0647 \u062f\u0631 \u0647\u0631 \u06a9\u0627\u0631\u062a\u0646 \u0631\u0633\u06cc\u062f\u060c \u0628\u0627\u0631\u06a9\u062f \u0645\u0627\u062f\u0631 \u06cc\u0648\u0646\u06cc\u06a9 \u06a9\u0627\u0631\u062a\u0646 \u0633\u0627\u062e\u062a\u0647 \u0648 \u0628\u0647 label printer \u062f\u0627\u062f\u0647 \u0645\u06cc\u200c\u0634\u0648\u062f. \u0628\u062e\u0634\u200c\u0647\u0627\u06cc \u0627\u0646\u0628\u0627\u0631\u060c \u062a\u0648\u0632\u06cc\u0639 \u0648 \u0645\u0631\u062c\u0648\u0639\u06cc \u0628\u0627 \u0627\u0633\u06a9\u0646 \u0628\u0627\u0631\u06a9\u062f\u0647\u0627 \u0648\u0636\u0639\u06cc\u062a \u0631\u0627 \u0628\u0647\u200c\u0631\u0648\u0632 \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f \u0648 \u06af\u0632\u0627\u0631\u0634\u200c\u06af\u06cc\u0631\u06cc \u0648 \u0622\u0645\u0627\u0631 \u06a9\u0627\u0645\u0644 \u062f\u0631 \u062f\u0633\u062a\u0631\u0633 \u0627\u0633\u062a.")
B.Rp=new A.Z("Tracking products manually across production, packaging, warehouse, distribution, and returns caused labeling errors, lost inventory visibility, and no single source of truth for product status.","\u0631\u0647\u06af\u06cc\u0631\u06cc \u062f\u0633\u062a\u06cc \u0645\u062d\u0635\u0648\u0644 \u062f\u0631 \u062a\u0648\u0644\u06cc\u062f\u060c \u0628\u0633\u062a\u0647\u200c\u0628\u0646\u062f\u06cc\u060c \u0627\u0646\u0628\u0627\u0631\u060c \u062a\u0648\u0632\u06cc\u0639 \u0648 \u0645\u0631\u062c\u0648\u0639\u06cc \u0628\u0627\u0639\u062b \u062e\u0637\u0627\u06cc \u0644\u06cc\u0628\u0644\u060c \u0627\u0632 \u062f\u0633\u062a \u0631\u0641\u062a\u0646 \u062f\u06cc\u062f \u0645\u0648\u062c\u0648\u062f\u06cc \u0648 \u0646\u0628\u0648\u062f \u0645\u0646\u0628\u0639 \u0648\u0627\u062d\u062f \u0628\u0631\u0627\u06cc \u0648\u0636\u0639\u06cc\u062a \u0645\u062d\u0635\u0648\u0644 \u0645\u06cc\u200c\u0634\u062f.")
B.Rk=new A.Z("Built with Django, Redis, Celery, and MySQL \u2014 dynamic QR/barcode generation rules per product type, Jet Printer and label printer integrations, camera-based scanning workflows, automatic master carton barcode creation when unit count per carton is met, and status management modules for warehouse, distribution, and returns with comprehensive analytics dashboards.","\u0628\u0627 Django\u060c Redis\u060c Celery \u0648 MySQL \u2014 \u0642\u0648\u0627\u0646\u06cc\u0646 \u067e\u0648\u06cc\u0627 \u0628\u0631\u0627\u06cc \u062a\u0648\u0644\u06cc\u062f QR/\u0628\u0627\u0631\u06a9\u062f \u0628\u0631 \u0627\u0633\u0627\u0633 \u0646\u0648\u0639 \u0645\u062d\u0635\u0648\u0644\u060c \u0627\u062a\u0635\u0627\u0644 Jet Printer \u0648 label printer\u060c \u06af\u0631\u062f\u0634 \u06a9\u0627\u0631 \u0627\u0633\u06a9\u0646 \u0628\u0627 \u062f\u0648\u0631\u0628\u06cc\u0646\u060c \u0633\u0627\u062e\u062a \u062e\u0648\u062f\u06a9\u0627\u0631 \u0628\u0627\u0631\u06a9\u062f \u0645\u0627\u062f\u0631 \u06a9\u0627\u0631\u062a\u0646 \u062f\u0631 \u0631\u0633\u06cc\u062f\u0646 \u0628\u0647 \u062a\u0639\u062f\u0627\u062f \u0648\u0627\u062d\u062f\u060c \u0648 \u0645\u0627\u0698\u0648\u0644\u200c\u0647\u0627\u06cc \u0648\u0636\u0639\u06cc\u062a \u0628\u0631\u0627\u06cc \u0627\u0646\u0628\u0627\u0631\u060c \u062a\u0648\u0632\u06cc\u0639 \u0648 \u0645\u0631\u062c\u0648\u0639\u06cc \u0647\u0645\u0631\u0627\u0647 \u062f\u0627\u0634\u0628\u0648\u0631\u062f \u0622\u0645\u0627\u0631.")
B.RQ=new A.Z("Full traceability from production to returns, automated unit and carton labeling, real-time status updates across departments, and complete reporting for operational decisions.","\u0631\u062f\u06cc\u0627\u0628\u06cc \u06a9\u0627\u0645\u0644 \u0627\u0632 \u062a\u0648\u0644\u06cc\u062f \u062a\u0627 \u0645\u0631\u062c\u0648\u0639\u06cc\u060c \u0644\u06cc\u0628\u0644\u200c\u06af\u0630\u0627\u0631\u06cc \u062e\u0648\u062f\u06a9\u0627\u0631 \u0648\u0627\u062d\u062f \u0648 \u06a9\u0627\u0631\u062a\u0646\u060c \u0628\u0647\u200c\u0631\u0648\u0632\u0631\u0633\u0627\u0646\u06cc \u0644\u062d\u0638\u0647\u200c\u0627\u06cc \u0648\u0636\u0639\u06cc\u062a \u0628\u06cc\u0646 \u0628\u062e\u0634\u200c\u0647\u0627\u060c \u0648 \u06af\u0632\u0627\u0631\u0634\u200c\u06af\u06cc\u0631\u06cc \u06a9\u0627\u0645\u0644 \u0628\u0631\u0627\u06cc \u062a\u0635\u0645\u06cc\u0645\u200c\u06af\u06cc\u0631\u06cc \u0639\u0645\u0644\u06cc\u0627\u062a\u06cc.")
