B.Rc=new A.Z("Django backend for an AI-powered language learning app \u2014 custom courses, chat assistants, and creator monetization.","\u0628\u06a9\u200c\u0627\u0646\u062f Django \u0628\u0631\u0627\u06cc \u0627\u067e \u06cc\u0627\u062f\u06af\u06cc\u0631\u06cc \u0632\u0628\u0627\u0646 \u0628\u0627 AI \u2014 \u062f\u0648\u0631\u0647 \u0633\u0641\u0627\u0631\u0634\u06cc\u060c \u062f\u0633\u062a\u06cc\u0627\u0631 \u0686\u062a \u0648 \u062f\u0631\u0622\u0645\u062f\u0632\u0627\u06cc\u06cc \u0628\u0631\u0627\u06cc \u0633\u0627\u0632\u0646\u062f\u06af\u0627\u0646.")
