B.Qz=new A.Z("Backend platform for an AI-driven language learning application. Users can create structured language courses \u2014 comprehensive programs, grammar, reading, and more \u2014 and attach intelligent assistants to each course. Assistant bots answer learner questions via chat about course content, while specialized teaching bots can drill vocabulary, grammar, and other skills. Other users discover and enroll in published courses and bots. The platform includes a monetization system so course and bot creators can earn revenue from their content.","\u0628\u06a9\u200c\u0627\u0646\u062f \u067e\u0644\u062a\u0641\u0631\u0645 \u0627\u067e \u06cc\u0627\u062f\u06af\u06cc\u0631\u06cc \u0632\u0628\u0627\u0646 \u0645\u0628\u062a\u0646\u06cc \u0628\u0631 \u0647\u0648\u0634 \u0645\u0635\u0646\u0648\u0639\u06cc. \u06a9\u0627\u0631\u0628\u0631\u0627\u0646 \u062f\u0648\u0631\u0647\u200c\u0647\u0627\u06cc \u0633\u0627\u062e\u062a\u0627\u0631\u06cc\u0627\u0641\u062a\u0647 \u0645\u06cc\u200c\u0633\u0627\u0632\u0646\u062f \u2014 \u062f\u0648\u0631\u0647 \u062c\u0627\u0645\u0639\u060c \u06af\u0631\u0627\u0645\u0631\u060c \u0631\u06cc\u062f\u06cc\u0646\u06af \u0648 ... \u2014 \u0648 \u0628\u0647 \u0647\u0631 \u062f\u0648\u0631\u0647 \u062f\u0633\u062a\u06cc\u0627\u0631 \u0647\u0648\u0634\u0645\u0646\u062f \u062a\u0639\u06cc\u06cc\u0646 \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f. \u0631\u0628\u0627\u062a \u062f\u0633\u062a\u06cc\u0627\u0631 \u062f\u0631 \u0642\u0627\u0644\u0628 \u0686\u062a \u0628\u0647 \u0633\u0648\u0627\u0644\u0627\u062a \u06cc\u0627\u062f\u06af\u06cc\u0631\u0646\u062f\u06af\u0627\u0646 \u062f\u0631\u0628\u0627\u0631\u0647 \u0645\u062d\u062a\u0648\u0627\u06cc \u062f\u0648\u0631\u0647 \u067e\u0627\u0633\u062e \u0645\u06cc\u200c\u062f\u0647\u062f\u061b \u0631\u0628\u0627\u062a\u200c\u0647\u0627\u06cc \u0622\u0645\u0648\u0632\u0634\u06cc \u0647\u0645 \u0628\u0631\u0627\u06cc \u06a9\u0627\u0631 \u0631\u0648\u06cc \u0644\u063a\u0627\u062a\u060c \u06af\u0631\u0627\u0645\u0631 \u0648 \u0645\u0647\u0627\u0631\u062a\u200c\u0647\u0627\u06cc \u062f\u06cc\u06af\u0631 \u0633\u0627\u062e\u062a\u0647 \u0645\u06cc\u200c\u0634\u0648\u0646\u062f. \u0633\u0627\u06cc\u0631 \u06a9\u0627\u0631\u0628\u0631\u0627\u0646 \u062f\u0648\u0631\u0647\u200c\u0647\u0627 \u0648 \u0631\u0628\u0627\u062a\u200c\u0647\u0627 \u0631\u0627 \u06a9\u0634\u0641 \u0648 \u0627\u0633\u062a\u0641\u0627\u062f\u0647 \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f. \u0633\u06cc\u0633\u062a\u0645 \u062f\u0631\u0622\u0645\u062f\u0632\u0627\u06cc\u06cc \u0628\u0631\u0627\u06cc \u0633\u0627\u0632\u0646\u062f\u06af\u0627\u0646 \u062f\u0648\u0631\u0647 \u0648 \u0631\u0628\u0627\u062a \u0647\u0645 \u067e\u06cc\u0627\u062f\u0647\u200c\u0633\u0627\u0632\u06cc \u0634\u062f\u0647 \u0627\u0633\u062a.")
B.S6=new A.Z("Language learners needed personalized, interactive content beyond static lessons \u2014 and educators lacked a platform to build, share, and monetize AI-enhanced courses without building everything from scratch.","\u0632\u0628\u0627\u0646\u200c\u0622\u0645\u0648\u0632\u0627\u0646 \u0628\u0647 \u0645\u062d\u062a\u0648\u0627\u06cc \u062a\u0639\u0627\u0645\u0644\u06cc \u0648 \u0634\u062e\u0635\u06cc\u200c\u0633\u0627\u0632\u06cc\u200c\u0634\u062f\u0647 \u0641\u0631\u0627\u062a\u0631 \u0627\u0632 \u062f\u0631\u0633\u200c\u0647\u0627\u06cc \u062b\u0627\u0628\u062a \u0646\u06cc\u0627\u0632 \u062f\u0627\u0634\u062a\u0646\u062f \u2014 \u0648 \u0645\u062f\u0631\u0633\u0627\u0646 \u067e\u0644\u062a\u0641\u0631\u0645\u06cc \u0628\u0631\u0627\u06cc \u0633\u0627\u062e\u062a\u060c \u0627\u0634\u062a\u0631\u0627\u06a9 \u0648 \u062f\u0631\u0622\u0645\u062f\u0632\u0627\u06cc\u06cc \u0627\u0632 \u062f\u0648\u0631\u0647\u200c\u0647\u0627\u06cc AI-enhanced \u0628\u062f\u0648\u0646 \u0633\u0627\u062e\u062a \u0647\u0645\u0647\u200c\u0686\u06cc\u0632 \u0627\u0632 \u0635\u0641\u0631 \u0646\u062f\u0627\u0634\u062a\u0646\u062f.")
B.QH=new A.Z("Built the backend with Django and integrated AI APIs for conversational assistants and teaching bots. Implemented course creation workflows (comprehensive, grammar, reading, etc.), per-course chat assistants, specialized bots for vocabulary and grammar practice, user enrollment, and a creator monetization engine \u2014 enabling a marketplace-style learning ecosystem.","\u0628\u06a9\u200c\u0627\u0646\u062f \u0628\u0627 Django \u0648 \u06cc\u06a9\u067e\u0627\u0631\u0686\u0647\u200c\u0633\u0627\u0632\u06cc AI API \u0628\u0631\u0627\u06cc \u062f\u0633\u062a\u06cc\u0627\u0631 \u0645\u06a9\u0627\u0644\u0645\u0647\u200c\u0627\u06cc \u0648 \u0631\u0628\u0627\u062a\u200c\u0647\u0627\u06cc \u0622\u0645\u0648\u0632\u0634\u06cc. \u06af\u0631\u062f\u0634 \u06a9\u0627\u0631 \u0633\u0627\u062e\u062a \u062f\u0648\u0631\u0647 (\u062c\u0627\u0645\u0639\u060c \u06af\u0631\u0627\u0645\u0631\u060c \u0631\u06cc\u062f\u06cc\u0646\u06af \u0648 ...)\u060c \u062f\u0633\u062a\u06cc\u0627\u0631 \u0686\u062a \u0628\u0631\u0627\u06cc \u0647\u0631 \u062f\u0648\u0631\u0647\u060c \u0631\u0628\u0627\u062a\u200c\u0647\u0627\u06cc \u062a\u062e\u0635\u0635\u06cc \u0644\u063a\u062a \u0648 \u06af\u0631\u0627\u0645\u0631\u060c \u062b\u0628\u062a\u200c\u0646\u0627\u0645 \u06a9\u0627\u0631\u0628\u0631\u0627\u0646 \u0648 \u0645\u0648\u062a\u0648\u0631 \u062f\u0631\u0622\u0645\u062f\u0632\u0627\u06cc\u06cc \u0633\u0627\u0632\u0646\u062f\u06af\u0627\u0646 \u2014 \u0627\u06a9\u0648\u0633\u06cc\u0633\u062a\u0645 \u06cc\u0627\u062f\u06af\u06cc\u0631\u06cc \u0634\u0628\u06cc\u0647 marketplace.")
B.QE=new A.Z("Creators can publish courses and bots, learners get AI-powered interactive tutoring, and the monetization layer supports sustainable content creation on the platform.","\u0633\u0627\u0632\u0646\u062f\u06af\u0627\u0646 \u062f\u0648\u0631\u0647 \u0648 \u0631\u0628\u0627\u062a \u0645\u0646\u062a\u0634\u0631 \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f\u060c \u06cc\u0627\u062f\u06af\u06cc\u0631\u0646\u062f\u06af\u0627\u0646 \u0622\u0645\u0648\u0632\u0634 \u062a\u0639\u0627\u0645\u0644\u06cc \u0628\u0627 AI \u0645\u06cc\u200c\u06af\u06cc\u0631\u0646\u062f \u0648 \u0644\u0627\u06cc\u0647 \u062f\u0631\u0622\u0645\u062f\u0632\u0627\u06cc\u06cc \u062e\u0644\u0642 \u0645\u062d\u062a\u0648\u0627\u06cc \u067e\u0627\u06cc\u062f\u0627\u0631 \u0631\u0627 \u067e\u0634\u062a\u06cc\u0628\u0627\u0646\u06cc \u0645\u06cc\u200c\u06a9\u0646\u062f.")
