B.RA=new A.Z("A dynamic single-page developer portfolio built with Flutter for web. Showcases selected projects with full bilingual case study pages, grouped skills with brand icons, work experience and education timelines, and contact channels \u2014 all with smooth animations, dark/light theme toggle, and a developer-themed background. Deploy-ready for GitHub Pages and Firebase Hosting.","\u067e\u0648\u0631\u062a\u0641\u0648\u0644\u06cc\u0648 \u062a\u06a9\u200c\u0635\u0641\u062d\u0647\u200c\u0627\u06cc \u067e\u0648\u06cc\u0627 \u0628\u0627 Flutter \u0628\u0631\u0627\u06cc \u0648\u0628. \u0646\u0645\u0627\u06cc\u0634 \u067e\u0631\u0648\u0698\u0647\u200c\u0647\u0627\u06cc \u0645\u0646\u062a\u062e\u0628 \u0628\u0627 \u0635\u0641\u062d\u0627\u062a case study \u062f\u0648\u0632\u0628\u0627\u0646\u0647\u060c \u0645\u0647\u0627\u0631\u062a\u200c\u0647\u0627\u06cc \u06af\u0631\u0648\u0647\u200c\u0628\u0646\u062f\u06cc\u200c\u0634\u062f\u0647 \u0628\u0627 \u0622\u06cc\u06a9\u0648\u0646 \u0628\u0631\u0646\u062f\u060c timeline \u062a\u062c\u0631\u0628\u0647 \u0648 \u062a\u062d\u0635\u06cc\u0644\u0627\u062a\u060c \u0648 \u0631\u0627\u0647\u200c\u0647\u0627\u06cc \u0627\u0631\u062a\u0628\u0627\u0637\u06cc \u2014 \u0647\u0645\u0631\u0627\u0647 \u0627\u0646\u06cc\u0645\u06cc\u0634\u0646\u200c\u0647\u0627\u06cc \u0631\u0648\u0627\u0646\u060c \u062a\u0645 \u0631\u0648\u0634\u0646/\u062a\u06cc\u0631\u0647 \u0648 \u067e\u0633\u200c\u0632\u0645\u06cc\u0646\u0647 \u062a\u0645 \u0628\u0631\u0646\u0627\u0645\u0647\u200c\u0646\u0648\u06cc\u0633\u06cc. \u0622\u0645\u0627\u062f\u0647 deploy \u0631\u0648\u06cc GitHub Pages \u0648 Firebase Hosting.")
B.R_=new A.Z("Needed a professional online presence that presents projects in depth, supports both English and Persian audiences, and clearly communicates full-stack skills \u2014 without relying on a generic template site builder.","\u0646\u06cc\u0627\u0632 \u0628\u0647 \u062d\u0636\u0648\u0631 \u0622\u0646\u0644\u0627\u06cc\u0646 \u062d\u0631\u0641\u0647\u200c\u0627\u06cc \u0628\u0631\u0627\u06cc \u0646\u0645\u0627\u06cc\u0634 \u0639\u0645\u06cc\u0642 \u067e\u0631\u0648\u0698\u0647\u200c\u0647\u0627\u060c \u067e\u0634\u062a\u06cc\u0628\u0627\u0646\u06cc \u0627\u0632 \u0645\u062e\u0627\u0637\u0628 \u0641\u0627\u0631\u0633\u06cc \u0648 \u0627\u0646\u06af\u0644\u06cc\u0633\u06cc\u060c \u0648 \u0627\u0646\u062a\u0642\u0627\u0644 \u0634\u0641\u0627\u0641 \u0645\u0647\u0627\u0631\u062a\u200c\u0647\u0627\u06cc \u0641\u0648\u0644\u200c\u0627\u0633\u062a\u06a9 \u2014 \u0628\u062f\u0648\u0646 \u0648\u0627\u0628\u0633\u062a\u06af\u06cc \u0628\u0647 \u0633\u0627\u06cc\u062a\u200c\u0633\u0627\u0632\u0647\u0627\u06cc \u0622\u0645\u0627\u062f\u0647.")
B.Sm=new A.Z("Built with Flutter \u2014 modular section architecture, ARB-based localization with RTL layout, Provider for theme/locale state, routed project detail screens, Simple Icons CDN for skill branding, animated hero and skills UI, and CI deploy configs for GitHub Pages and Firebase.","\u0628\u0627 Flutter \u2014 \u0645\u0639\u0645\u0627\u0631\u06cc \u0645\u0627\u0698\u0648\u0644\u0627\u0631 \u0628\u062e\u0634\u200c\u0647\u0627\u060c localization \u0645\u0628\u062a\u0646\u06cc \u0628\u0631 ARB \u0628\u0627 layout RTL\u060c Provider \u0628\u0631\u0627\u06cc \u062a\u0645/\u0632\u0628\u0627\u0646\u060c \u0635\u0641\u062d\u0627\u062a \u062c\u0632\u0626\u06cc\u0627\u062a \u067e\u0631\u0648\u0698\u0647 \u0628\u0627 routing\u060c CDN Simple Icons \u0628\u0631\u0627\u06cc \u0628\u0631\u0646\u062f \u0645\u0647\u0627\u0631\u062a\u200c\u0647\u0627\u060c UI \u0627\u0646\u06cc\u0645\u06cc\u0634\u0646\u200c\u062f\u0627\u0631 hero \u0648 skills\u060c \u0648 \u062a\u0646\u0638\u06cc\u0645\u0627\u062a CI \u0628\u0631\u0627\u06cc GitHub Pages \u0648 Firebase.")
