B.Ro=new A.Z("Local music player for mobile \u2014 smart filtering, playlists, favorites, shuffle, and built-in equalizer.","\u067e\u062e\u0634\u200c\u06a9\u0646\u0646\u062f\u0647 \u0645\u0648\u0633\u06cc\u0642\u06cc \u0645\u062d\u0644\u06cc \u0645\u0648\u0628\u0627\u06cc\u0644 \u2014 \u0641\u06cc\u0644\u062a\u0631 \u0647\u0648\u0634\u0645\u0646\u062f\u060c \u067e\u0644\u06cc\u200c\u0644\u06cc\u0633\u062a\u060c \u0639\u0644\u0627\u0642\u0647\u200c\u0645\u0646\u062f\u06cc\u060c shuffle \u0648 \u0627\u06a9\u0648\u0644\u0627\u06cc\u0632\u0631.")
