B.Qy=new A.Z("A Flutter music player that scans and lists all songs on the device, sortable by date or name. Users can play tracks sequentially or in shuffle mode. Configurable filters exclude songs shorter than a set duration or below a minimum file size from the library and playback. Full playlist creation, favorite marking, and a built-in equalizer for custom audio tuning round out the experience.","\u0645\u0648\u0632\u06cc\u06a9 \u067e\u0644\u06cc\u0631 Flutter \u06a9\u0647 \u0622\u0647\u0646\u06af\u200c\u0647\u0627\u06cc \u062f\u0633\u062a\u06af\u0627\u0647 \u0631\u0627 \u0627\u0633\u06a9\u0646 \u0648 \u0644\u06cc\u0633\u062a \u0645\u06cc\u200c\u06a9\u0646\u062f \u2014 \u0645\u0631\u062a\u0628\u200c\u0633\u0627\u0632\u06cc \u0628\u0631 \u0627\u0633\u0627\u0633 \u0632\u0645\u0627\u0646 \u06cc\u0627 \u0646\u0627\u0645. \u067e\u062e\u0634 \u062a\u0631\u062a\u06cc\u0628\u06cc \u06cc\u0627 \u062a\u0635\u0627\u062f\u0641\u06cc (shuffle). \u0641\u06cc\u0644\u062a\u0631 \u0642\u0627\u0628\u0644 \u062a\u0646\u0638\u06cc\u0645: \u062d\u0630\u0641 \u0622\u0647\u0646\u06af\u200c\u0647\u0627\u06cc \u06a9\u0648\u062a\u0627\u0647\u200c\u062a\u0631 \u0627\u0632 m \u062f\u0642\u06cc\u0642\u0647 \u06cc\u0627 \u06a9\u0648\u0686\u06a9\u200c\u062a\u0631 \u0627\u0632 n \u062d\u062c\u0645 \u0627\u0632 \u0644\u06cc\u0633\u062a \u0648 \u067e\u062e\u0634. \u0633\u0627\u062e\u062a \u067e\u0644\u06cc\u200c\u0644\u06cc\u0633\u062a\u060c favorite \u06a9\u0631\u062f\u0646 \u0622\u0647\u0646\u06af\u200c\u0647\u0627 \u0648 \u0627\u06a9\u0648\u0644\u0627\u06cc\u0632\u0631 \u062f\u0627\u062e\u0644\u06cc \u0628\u0631\u0627\u06cc \u062a\u0646\u0638\u06cc\u0645 \u0635\u062f\u0627.")
B.RO=new A.Z("Default mobile music apps often lack fine-grained control \u2014 filtering short clips and small files, custom playlists, favorites, and equalizer settings in one lightweight local player.","\u0627\u067e\u200c\u0647\u0627\u06cc \u067e\u06cc\u0634\u200c\u0641\u0631\u0636 \u0645\u0648\u0633\u06cc\u0642\u06cc \u0645\u0648\u0628\u0627\u06cc\u0644 \u06a9\u0646\u062a\u0631\u0644 \u062f\u0642\u06cc\u0642 \u0646\u062f\u0627\u0631\u0646\u062f \u2014 \u0641\u06cc\u0644\u062a\u0631 \u06a9\u0644\u06cc\u067e \u06a9\u0648\u062a\u0627\u0647 \u0648 \u0641\u0627\u06cc\u0644 \u06a9\u0648\u0686\u06a9\u060c \u067e\u0644\u06cc\u200c\u0644\u06cc\u0633\u062a \u0633\u0641\u0627\u0631\u0634\u06cc\u060c favorite \u0648 \u0627\u06a9\u0648\u0644\u0627\u06cc\u0632\u0631 \u062f\u0631 \u06cc\u06a9 \u067e\u062e\u0634\u200c\u06a9\u0646\u0646\u062f\u0647 \u0633\u0628\u06a9 \u0645\u062d\u0644\u06cc.")
B.Sg=new A.Z("Built with Flutter \u2014 device media library integration, sort by name or date, sequential and shuffle playback, threshold filters for minimum duration and file size, playlist CRUD, favorites system, and native-style equalizer presets and custom bands.","\u0628\u0627 Flutter \u2014 \u0627\u062a\u0635\u0627\u0644 \u0628\u0647 \u06a9\u062a\u0627\u0628\u062e\u0627\u0646\u0647 \u0645\u062f\u06cc\u0627 \u062f\u0633\u062a\u06af\u0627\u0647\u060c \u0645\u0631\u062a\u0628\u200c\u0633\u0627\u0632\u06cc \u0646\u0627\u0645/\u0632\u0645\u0627\u0646\u060c \u067e\u062e\u0634 \u062a\u0631\u062a\u06cc\u0628\u06cc \u0648 shuffle\u060c \u0641\u06cc\u0644\u062a\u0631 \u062d\u062f\u0627\u0642\u0644 \u0645\u062f\u062a \u0648 \u062d\u062c\u0645 \u0641\u0627\u06cc\u0644\u060c CRUD \u067e\u0644\u06cc\u200c\u0644\u06cc\u0633\u062a\u060c \u0633\u06cc\u0633\u062a\u0645 \u0639\u0644\u0627\u0642\u0647\u200c\u0645\u0646\u062f\u06cc \u0648 preset \u0648 band \u0633\u0641\u0627\u0631\u0634\u06cc \u0627\u06a9\u0648\u0644\u0627\u06cc\u0632\u0631.")
B.RE=new A.Z("A polished offline music experience with smart library management, personal playlists, and full audio customization \u2014 no streaming dependency required.","\u062a\u062c\u0631\u0628\u0647 \u0645\u0648\u0633\u06cc\u0642\u06cc offline \u0628\u0627 \u0645\u062f\u06cc\u0631\u06cc\u062a \u0647\u0648\u0634\u0645\u0646\u062f \u06a9\u062a\u0627\u0628\u062e\u0627\u0646\u0647\u060c \u067e\u0644\u06cc\u200c\u0644\u06cc\u0633\u062a \u0634\u062e\u0635\u06cc \u0648 \u0633\u0641\u0627\u0631\u0634\u06cc\u200c\u0633\u0627\u0632\u06cc \u06a9\u0627\u0645\u0644 \u0635\u062f\u0627 \u2014 \u0628\u062f\u0648\u0646 \u0648\u0627\u0628\u0633\u062a\u06af\u06cc \u0628\u0647 streaming.")
