B.QD=new A.Z("A Django-based online appointment scheduling platform for clinics. Clinic administrators define their available time slots on the website, and patients browse open appointments and reserve the time that suits them \u2014 replacing phone-based booking with a self-service digital flow.","\u067e\u0644\u062a\u0641\u0631\u0645 \u0631\u0632\u0631\u0648 \u0646\u0648\u0628\u062a \u0622\u0646\u0644\u0627\u06cc\u0646 \u0645\u0628\u062a\u0646\u06cc \u0628\u0631 Django \u0628\u0631\u0627\u06cc \u06a9\u0644\u06cc\u0646\u06cc\u06a9\u200c\u0647\u0627. \u0645\u0633\u0626\u0648\u0644 \u06a9\u0644\u06cc\u0646\u06cc\u06a9 \u0646\u0648\u0628\u062a\u200c\u0647\u0627\u06cc \u062e\u0627\u0644\u06cc \u0631\u0627 \u062f\u0631 \u0633\u0627\u06cc\u062a \u062a\u0639\u06cc\u06cc\u0646 \u0645\u06cc\u200c\u06a9\u0646\u062f \u0648 \u0645\u0634\u062a\u0631\u06cc\u0627\u0646/\u0628\u06cc\u0645\u0627\u0631\u0627\u0646 \u0628\u0627 \u062a\u0648\u062c\u0647 \u0628\u0647 \u0632\u0645\u0627\u0646\u200c\u0647\u0627\u06cc \u0622\u0632\u0627\u062f\u060c \u0647\u0631 \u062a\u0627\u06cc\u0645\u06cc \u06a9\u0647 \u0628\u062e\u0648\u0627\u0647\u0646\u062f \u0631\u0632\u0631\u0648 \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f \u2014 \u062c\u0627\u06cc\u06af\u0632\u06cc\u0646 \u0646\u0648\u0628\u062a\u200c\u06af\u06cc\u0631\u06cc \u062a\u0644\u0641\u0646\u06cc \u0628\u0627 \u062c\u0631\u06cc\u0627\u0646 \u062f\u06cc\u062c\u06cc\u062a\u0627\u0644 self-service.")
B.Rf=new A.Z("Phone-only appointment booking caused double bookings, staff overhead, and patients unable to see real-time availability outside business hours.","\u0646\u0648\u0628\u062a\u200c\u06af\u06cc\u0631\u06cc \u0641\u0642\u0637 \u062a\u0644\u0641\u0646\u06cc \u0628\u0627\u0639\u062b \u0631\u0632\u0631\u0648 \u062a\u06a9\u0631\u0627\u0631\u06cc\u060c \u0628\u0627\u0631 \u06a9\u0627\u0631\u06cc \u067e\u0631\u0633\u0646\u0644 \u0648 \u0646\u0627\u062a\u0648\u0627\u0646\u06cc \u0628\u06cc\u0645\u0627\u0631\u0627\u0646 \u062f\u0631 \u062f\u06cc\u062f\u0646 \u0632\u0645\u0627\u0646\u200c\u0647\u0627\u06cc \u0622\u0632\u0627\u062f \u062e\u0627\u0631\u062c \u0627\u0632 \u0633\u0627\u0639\u0627\u062a \u06a9\u0627\u0631\u06cc \u0645\u06cc\u200c\u0634\u062f.")
B.RD=new A.Z("Built with Django \u2014 admin panel for clinic managers to create and manage available slots, public booking interface for patients to view open times and confirm reservations, with slot locking to prevent conflicts.","\u0628\u0627 Django \u2014 \u067e\u0646\u0644 \u0645\u062f\u06cc\u0631\u06cc\u062a \u0628\u0631\u0627\u06cc \u062a\u0639\u0631\u06cc\u0641 \u0648 \u0645\u062f\u06cc\u0631\u06cc\u062a \u0627\u0633\u0644\u0627\u062a\u200c\u0647\u0627\u06cc \u062e\u0627\u0644\u06cc\u060c \u0631\u0627\u0628\u0637 \u0639\u0645\u0648\u0645\u06cc \u0628\u0631\u0627\u06cc \u0645\u0634\u0627\u0647\u062f\u0647 \u0632\u0645\u0627\u0646\u200c\u0647\u0627\u06cc \u0622\u0632\u0627\u062f \u0648 \u062a\u0623\u06cc\u06cc\u062f \u0631\u0632\u0631\u0648\u060c \u0628\u0627 \u0642\u0641\u0644 \u0627\u0633\u0644\u0627\u062a \u0628\u0631\u0627\u06cc \u062c\u0644\u0648\u06af\u06cc\u0631\u06cc \u0627\u0632 \u062a\u062f\u0627\u062e\u0644.")
B.QL=new A.Z("Streamlined clinic scheduling, reduced phone load, 24/7 self-service booking for patients, and clear visibility of available appointments.","\u0632\u0645\u0627\u0646\u200c\u0628\u0646\u062f\u06cc \u0631\u0648\u0627\u0646 \u06a9\u0644\u06cc\u0646\u06cc\u06a9\u060c \u06a9\u0627\u0647\u0634 \u062a\u0645\u0627\u0633 \u062a\u0644\u0641\u0646\u06cc\u060c \u0631\u0632\u0631\u0648 self-service \u06f2\u06f4/\u06f7 \u0628\u0631\u0627\u06cc \u0628\u06cc\u0645\u0627\u0631\u0627\u0646 \u0648 \u062f\u06cc\u062f \u0634\u0641\u0627\u0641 \u0646\u0648\u0628\u062a\u200c\u0647\u0627\u06cc \u062e\u0627\u0644\u06cc.")
