B.Rt=new A.Z("Frontend mobile application built with Ionic for an IoT security platform focused on alarm systems and GPS trackers. Users register devices in the app, connect to them over the network, and apply remote configuration settings. When a device detects a tracked event or trigger, it sends data to the backend server, which forwards real-time push notifications to the user's phone.","\u0627\u067e \u0645\u0648\u0628\u0627\u06cc\u0644 Ionic \u0628\u0631\u0627\u06cc \u067e\u0644\u062a\u0641\u0631\u0645 IoT \u0627\u0645\u0646\u06cc\u062a\u06cc \u2014 \u062f\u0632\u062f\u06af\u06cc\u0631 \u0648 \u0631\u062f\u06cc\u0627\u0628 GPS. \u06a9\u0627\u0631\u0628\u0631\u0627\u0646 \u062f\u0633\u062a\u06af\u0627\u0647\u200c\u0647\u0627 \u0631\u0627 \u062f\u0631 \u0627\u067e \u062a\u0639\u0631\u06cc\u0641\u060c \u0628\u0647 \u0622\u0646\u200c\u0647\u0627 \u0645\u062a\u0635\u0644 \u0648 \u062a\u0646\u0638\u06cc\u0645\u0627\u062a \u0627\u0632 \u0631\u0627\u0647 \u062f\u0648\u0631 \u0627\u0639\u0645\u0627\u0644 \u0645\u06cc\u200c\u06a9\u0646\u0646\u062f. \u0648\u0642\u062a\u06cc \u062f\u0633\u062a\u06af\u0627\u0647 \u0631\u0648\u06cc\u062f\u0627\u062f \u06cc\u0627 trigger \u0631\u062f\u06cc\u0627\u0628\u06cc \u0631\u0627 \u062a\u0634\u062e\u06cc\u0635 \u062f\u0647\u062f\u060c \u062f\u0627\u062f\u0647 \u0628\u0647 \u0633\u0631\u0648\u0631 \u0627\u0631\u0633\u0627\u0644 \u0648 \u0633\u0631\u0648\u0631 push notification \u0644\u062d\u0638\u0647\u200c\u0627\u06cc \u0628\u0647 \u0645\u0648\u0628\u0627\u06cc\u0644 \u06a9\u0627\u0631\u0628\u0631 \u0645\u06cc\u200c\u0641\u0631\u0633\u062a\u062f.")
B.RK=new A.Z("IoT device management required a cross-platform mobile UI for pairing, live configuration, and instant alerts \u2014 without users needing technical knowledge of each tracker or alarm model.","\u0645\u062f\u06cc\u0631\u06cc\u062a \u062f\u0633\u062a\u06af\u0627\u0647 IoT \u0628\u0647 UI \u0645\u0648\u0628\u0627\u06cc\u0644 cross-platform \u0628\u0631\u0627\u06cc pairing\u060c \u062a\u0646\u0638\u06cc\u0645\u0627\u062a live \u0648 \u0647\u0634\u062f\u0627\u0631 \u0641\u0648\u0631\u06cc \u0646\u06cc\u0627\u0632 \u062f\u0627\u0634\u062a \u2014 \u0628\u062f\u0648\u0646 \u062f\u0627\u0646\u0634 \u0641\u0646\u06cc \u06a9\u0627\u0631\u0628\u0631 \u0627\u0632 \u0647\u0631 \u0645\u062f\u0644 \u0631\u062f\u06cc\u0627\u0628 \u06cc\u0627 \u062f\u0632\u062f\u06af\u06cc\u0631.")
B.R2=new A.Z("Built the frontend with Ionic \u2014 device registration and connection flows, remote settings panels per device type, real-time sync with backend API, and push notification integration so users are instantly notified when tracking events occur.","\u0641\u0631\u0627\u0646\u062a \u0628\u0627 Ionic \u2014 \u06af\u0631\u062f\u0634 \u062b\u0628\u062a \u0648 \u0627\u062a\u0635\u0627\u0644 \u062f\u0633\u062a\u06af\u0627\u0647\u060c \u067e\u0646\u0644 \u062a\u0646\u0638\u06cc\u0645\u0627\u062a \u0627\u0632 \u0631\u0627\u0647 \u062f\u0648\u0631 \u0628\u0631\u0627\u06cc \u0647\u0631 \u0646\u0648\u0639 \u062f\u0633\u062a\u06af\u0627\u0647\u060c \u0647\u0645\u06af\u0627\u0645\u200c\u0633\u0627\u0632\u06cc \u0644\u062d\u0638\u0647\u200c\u0627\u06cc \u0628\u0627 API \u0628\u06a9\u200c\u0627\u0646\u062f \u0648 \u06cc\u06a9\u067e\u0627\u0631\u0686\u0647\u200c\u0633\u0627\u0632\u06cc push notification \u0628\u0631\u0627\u06cc \u0627\u0639\u0644\u0627\u0646 \u0641\u0648\u0631\u06cc \u0631\u0648\u06cc\u062f\u0627\u062f\u0647\u0627\u06cc \u0631\u062f\u06cc\u0627\u0628\u06cc.")
B.So=new A.Z("Unified mobile control for alarms and trackers, remote device management from anywhere, and immediate push alerts when events are detected.","\u06a9\u0646\u062a\u0631\u0644 \u06cc\u06a9\u067e\u0627\u0631\u0686\u0647 \u0645\u0648\u0628\u0627\u06cc\u0644 \u062f\u0632\u062f\u06af\u06cc\u0631 \u0648 \u0631\u062f\u06cc\u0627\u0628\u060c \u0645\u062f\u06cc\u0631\u06cc\u062a \u0627\u0632 \u0631\u0627\u0647 \u062f\u0648\u0631 \u062f\u0633\u062a\u06af\u0627\u0647 \u0627\u0632 \u0647\u0631 \u062c\u0627\u060c \u0648 \u0647\u0634\u062f\u0627\u0631 push \u0641\u0648\u0631\u06cc \u0647\u0646\u06af\u0627\u0645 \u062a\u0634\u062e\u06cc\u0635 \u0631\u0648\u06cc\u062f\u0627\u062f.")
