B.Rq=new A.Z("Custom YOLO model training for automatic license plate detection in images and video streams.","\u0622\u0645\u0648\u0632\u0634 \u0645\u062f\u0644 YOLO \u0633\u0641\u0627\u0631\u0634\u06cc \u0628\u0631\u0627\u06cc \u062a\u0634\u062e\u06cc\u0635 \u062e\u0648\u062f\u06a9\u0627\u0631 \u067e\u0644\u0627\u06a9 \u062e\u0648\u062f\u0631\u0648 \u062f\u0631 \u062a\u0635\u0648\u06cc\u0631 \u0648 \u0648\u06cc\u062f\u06cc\u0648.")
