B.Qx=new A.Z("A computer vision project focused on training a YOLO object detection model to identify and localize vehicle license plates. The workflow covers dataset preparation and labeling, model training and hyperparameter tuning, evaluation with precision/recall metrics, and inference on real-world images and video frames \u2014 enabling automated plate detection for traffic, parking, or security use cases.","\u067e\u0631\u0648\u0698\u0647 \u0628\u06cc\u0646\u0627\u06cc\u06cc \u0645\u0627\u0634\u06cc\u0646 \u0628\u0631\u0627\u06cc \u0622\u0645\u0648\u0632\u0634 \u0645\u062f\u0644 \u062a\u0634\u062e\u06cc\u0635 \u0634\u06cc\u0621 YOLO \u062c\u0647\u062a \u0634\u0646\u0627\u0633\u0627\u06cc\u06cc \u0648 \u0645\u0648\u0642\u0639\u06cc\u062a\u200c\u06cc\u0627\u0628\u06cc \u067e\u0644\u0627\u06a9 \u062e\u0648\u062f\u0631\u0648. \u0634\u0627\u0645\u0644 \u0622\u0645\u0627\u062f\u0647\u200c\u0633\u0627\u0632\u06cc \u0648 label \u062f\u06cc\u062a\u0627\u0633\u062a\u060c \u0622\u0645\u0648\u0632\u0634 \u0645\u062f\u0644 \u0648 tuning\u060c \u0627\u0631\u0632\u06cc\u0627\u0628\u06cc \u0628\u0627 precision/recall \u0648 inference \u0631\u0648\u06cc \u062a\u0635\u0648\u06cc\u0631 \u0648 \u0641\u0631\u06cc\u0645 \u0648\u06cc\u062f\u06cc\u0648 \u2014 \u0628\u0631\u0627\u06cc \u06a9\u0627\u0631\u0628\u0631\u062f \u062a\u0631\u0627\u0641\u06cc\u06a9\u060c \u067e\u0627\u0631\u06a9\u06cc\u0646\u06af \u06cc\u0627 \u0627\u0645\u0646\u06cc\u062a.")
B.QA=new A.Z("Manual license plate reading does not scale for high-volume traffic monitoring \u2014 a reliable automated detector was needed that works across varied lighting, angles, and plate formats.","\u062e\u0648\u0627\u0646\u062f\u0646 \u062f\u0633\u062a\u06cc \u067e\u0644\u0627\u06a9 \u0628\u0631\u0627\u06cc \u067e\u0627\u06cc\u0634 \u067e\u0631\u062a\u0631\u0627\u0641\u06cc\u06a9 \u0645\u0642\u06cc\u0627\u0633\u200c\u067e\u0630\u06cc\u0631 \u0646\u06cc\u0633\u062a \u2014 \u0628\u0647 detector \u062e\u0648\u062f\u06a9\u0627\u0631 \u067e\u0627\u06cc\u062f\u0627\u0631 \u0646\u06cc\u0627\u0632 \u0628\u0648\u062f \u06a9\u0647 \u062f\u0631 \u0646\u0648\u0631\u060c \u0632\u0627\u0648\u06cc\u0647 \u0648 \u0641\u0631\u0645\u062a \u067e\u0644\u0627\u06a9 \u0645\u062e\u062a\u0644\u0641 \u06a9\u0627\u0631 \u06a9\u0646\u062f.")
B.QR=new A.Z("Prepared a labeled dataset of vehicle images, trained a YOLO model with iterative fine-tuning, validated detection accuracy on held-out samples, and deployed inference pipeline using Python, OpenCV, and PyTorch/Ultralytics stack.","\u062f\u06cc\u062a\u0627\u0633\u062a label\u200c\u0634\u062f\u0647 \u062a\u0635\u0627\u0648\u06cc\u0631 \u062e\u0648\u062f\u0631\u0648\u060c \u0622\u0645\u0648\u0632\u0634 YOLO \u0628\u0627 fine-tuning \u062a\u06a9\u0631\u0627\u0631\u06cc\u060c \u0627\u0639\u062a\u0628\u0627\u0631\u0633\u0646\u062c\u06cc \u062f\u0642\u062a \u0631\u0648\u06cc \u0646\u0645\u0648\u0646\u0647\u200c\u0647\u0627\u06cc test \u0648 pipeline inference \u0628\u0627 Python\u060c OpenCV \u0648 PyTorch/Ultralytics.")
B.Rb=new A.Z("A production-ready plate detection model capable of real-time inference \u2014 foundation for ANPR, parking systems, or traffic analytics pipelines.","\u0645\u062f\u0644 \u062a\u0634\u062e\u06cc\u0635 \u067e\u0644\u0627\u06a9 \u0622\u0645\u0627\u062f\u0647 inference \u0644\u062d\u0638\u0647\u200c\u0627\u06cc \u2014 \u067e\u0627\u06cc\u0647 \u0628\u0631\u0627\u06cc ANPR\u060c \u0633\u06cc\u0633\u062a\u0645 \u067e\u0627\u0631\u06a9\u06cc\u0646\u06af \u06cc\u0627 pipeline \u062a\u062d\u0644\u06cc\u0644 \u062a\u0631\u0627\u0641\u06cc\u06a9.")
