B.RZ=new A.Z("Jet Printer Excel & Scan Verification","\u0686\u0627\u067e Jet Printer \u0627\u0632 Excel \u0648 \u062a\u0623\u06cc\u06cc\u062f \u0628\u0627 \u0627\u0633\u06a9\u0646\u0631")
B.RG=new A.Z("Flutter desktop app \u2014 reads Excel files, sends print commands to industrial Jet Printers, and verifies output with a barcode scanner.","\u0627\u067e \u062f\u0633\u06a9\u062a\u0627\u067e Flutter \u2014 \u062e\u0648\u0627\u0646\u062f\u0646 \u0641\u0627\u06cc\u0644 Excel\u060c \u0627\u0631\u0633\u0627\u0644 \u062f\u0633\u062a\u0648\u0631 \u0686\u0627\u067e \u0628\u0647 Jet Printer \u0635\u0646\u0639\u062a\u06cc \u0648 \u0628\u0631\u0631\u0633\u06cc \u0635\u062d\u062a \u0686\u0627\u067e \u0628\u0627 \u0627\u0633\u06a9\u0646\u0631 \u0628\u0627\u0631\u06a9\u062f.")
