B.S4=new A.Z("A Flutter desktop application for production-line labeling workflows. Operators upload Excel files containing product data; the app parses rows and sends formatted print jobs to industrial Jet Printers. After printing, a barcode scanner verifies that the label was applied correctly \u2014 closing the loop between data import, print execution, and quality control.","\u0627\u067e \u062f\u0633\u06a9\u062a\u0627\u067e Flutter \u0628\u0631\u0627\u06cc \u06af\u0631\u062f\u0634 \u06a9\u0627\u0631 \u0644\u06cc\u0628\u0644\u200c\u06af\u0630\u0627\u0631\u06cc \u062e\u0637 \u062a\u0648\u0644\u06cc\u062f. \u0627\u067e\u0631\u0627\u062a\u0648\u0631 \u0641\u0627\u06cc\u0644 Excel \u062d\u0627\u0648\u06cc \u062f\u0627\u062f\u0647 \u0645\u062d\u0635\u0648\u0644 \u0631\u0627 \u0628\u0627\u0631\u06af\u0630\u0627\u0631\u06cc \u0645\u06cc\u200c\u06a9\u0646\u062f\u061b \u0627\u067e \u0633\u0637\u0631\u0647\u0627 \u0631\u0627 parse \u0648 \u062f\u0633\u062a\u0648\u0631 \u0686\u0627\u067e \u0641\u0631\u0645\u062a\u200c\u0634\u062f\u0647 \u0628\u0647 Jet Printer \u0635\u0646\u0639\u062a\u06cc \u0645\u06cc\u200c\u0641\u0631\u0633\u062a\u062f. \u067e\u0633 \u0627\u0632 \u0686\u0627\u067e\u060c \u0627\u0633\u06a9\u0646\u0631 \u0628\u0627\u0631\u06a9\u062f \u0635\u062d\u062a \u0627\u0639\u0645\u0627\u0644 \u0644\u06cc\u0628\u0644 \u0631\u0627 \u0628\u0631\u0631\u0633\u06cc \u0645\u06cc\u200c\u06a9\u0646\u062f \u2014 \u0628\u0633\u062a\u0646 \u062d\u0644\u0642\u0647 \u0628\u06cc\u0646 import \u062f\u0627\u062f\u0647\u060c \u0627\u062c\u0631\u0627\u06cc \u0686\u0627\u067e \u0648 \u06a9\u0646\u062a\u0631\u0644 \u06a9\u06cc\u0641\u06cc\u062a.")
B.RR=new A.Z("Manual label printing from spreadsheets caused misprints, no verification step, and slow handoff between office data and the production floor.","\u0686\u0627\u067e \u062f\u0633\u062a\u06cc \u0644\u06cc\u0628\u0644 \u0627\u0632 Excel \u0628\u0627\u0639\u062b \u0686\u0627\u067e \u0627\u0634\u062a\u0628\u0627\u0647\u060c \u0646\u0628\u0648\u062f \u0645\u0631\u062d\u0644\u0647 \u062a\u0623\u06cc\u06cc\u062f \u0648 \u0627\u0646\u062a\u0642\u0627\u0644 \u06a9\u0646\u062f \u062f\u0627\u062f\u0647 \u0628\u06cc\u0646 \u062f\u0641\u062a\u0631 \u0648 \u062e\u0637 \u062a\u0648\u0644\u06cc\u062f \u0645\u06cc\u200c\u0634\u062f.")
B.QN=new A.Z("Built with Flutter \u2014 Excel parsing and batch queue management, Jet Printer driver integration for industrial print commands, scanner input for post-print barcode verification, and operator-friendly UI for daily production use.","\u0628\u0627 Flutter \u2014 parse \u0648 \u0635\u0641 Excel\u060c \u0627\u062a\u0635\u0627\u0644 Jet Printer \u0628\u0631\u0627\u06cc \u062f\u0633\u062a\u0648\u0631 \u0686\u0627\u067e \u0635\u0646\u0639\u062a\u06cc\u060c \u0648\u0631\u0648\u062f\u06cc \u0627\u0633\u06a9\u0646\u0631 \u0628\u0631\u0627\u06cc \u062a\u0623\u06cc\u06cc\u062f \u0628\u0627\u0631\u06a9\u062f \u067e\u0633 \u0627\u0632 \u0686\u0627\u067e\u060c \u0648 UI \u0645\u0646\u0627\u0633\u0628 \u0627\u067e\u0631\u0627\u062a\u0648\u0631 \u0628\u0631\u0627\u06cc \u0627\u0633\u062a\u0641\u0627\u062f\u0647 \u0631\u0648\u0632\u0627\u0646\u0647 \u062a\u0648\u0644\u06cc\u062f.")
